  process.exit(1);
}

if (mode === "signup") {
  const unique = Date.now();
  const res = await fetch(`${supabaseUrl}/functions/v1/auth-signup-creator`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${anonKey}`,
      apikey: anonKey,
    },
